const webhookData = $('Webhook — Brand Profile Updated').item.json;
const p = webhookData.profile_payload || {};
const id = p.identity || {};
const personas = Array.isArray(p.personas) ? p.personas : [];
const tones = Array.isArray(p.tone_by_channel) ? p.tone_by_channel : [];
const samples = Array.isArray(p.content_samples) ? p.content_samples : [];

const personaList = personas.length
  ? personas.map(pe => `- ${pe.role || pe.label}: ${[pe.painPoints, pe.context].filter(Boolean).join('. ')}`).join('\n')
  : '- General business audience';

const toneList = tones.length
  ? tones.map(t => `- ${t.channel}: ${t.tone || ''} (${t.formality || ''}). ${t.examples || ''}`).join('\n')
  : '- Professional and direct';

const sampleRef = samples.length
  ? `\nExisting content references:\n${samples.slice(0, 3).map(s => `- "${s.title}" on ${s.channel}`).join('\n')}`
  : '';

const companyName = (id.company_name || 'BRAND').toUpperCase().replace(/[^A-Z0-9]/g, '').slice(0, 20);

const newConceptsInstruction = `Adapt this video for ${id.company_name || 'the brand'}.

About the brand: ${id.mission || id.tagline || ''}
Industry: ${id.industry || ''}

Target audience:
${personaList}

Brand tone by channel:
${toneList}${sampleRef}

Task:
Give us 3 NEW video concepts inspired by the ORIGINAL reference.
Do not copy the original. Translate the core idea into the ${id.industry || 'brand'} context.
MAINLY iterate and sharpen the HOOKS.

Focus:
- First 3 seconds must stop the target audience from scrolling
- Hooks should challenge a belief, fear, or misconception the audience has
- Match the brand tone per channel (listed above)
- No buzzwords, no exaggeration

Output format:

# CONCEPT 1
Text description (1-3 sentences)

## HOOK
- VISUAL: what is seen in the first 2 seconds
- SPOKEN: first line said (quote it)
- WHY IT WORKS: why this hook stops the viewer

## SCRIPT
Scene flow and spoken text (1-20 sentences)

# CONCEPT 2
...

# CONCEPT 3
...`;

return [{ json: {
  configName: companyName,
  creatorsCategory: companyName.toLowerCase(),
  newConceptsInstruction,
  brand_id: webhookData.brand_id,
} }];

const configs = $input.all().map(i => i.json);
const configName = $('Build newConceptsInstruction').item.json.configName;
const existing = configs.find(c => c.configName === configName);
return [{ json: {
  existing: existing || null,
  configName: $('Build newConceptsInstruction').item.json.configName,
  creatorsCategory: $('Build newConceptsInstruction').item.json.creatorsCategory,
  newConceptsInstruction: $('Build newConceptsInstruction').item.json.newConceptsInstruction,
} }];
